  reviews_7d: int('new_reviews_7d'),
  date: str('checked_at')
};

const ga = {
  sess_yd: int('sess_yd'), conv_yd: int('conv_yd'), rev_yd: str('rev_yd'),
  sess_7d: int('sess_7d'), rev_7d: str('rev_7d'),
  sess_30d: int('sess_30d'), conv_30d: int('conv_30d'), rev_30d: str('rev_30d'),
  avg_day: str('avg_rev_day'), cr30: str('cr30')
};

const tq = (d.top_queries || []).map(q => `${q.q}: ${q.clicks} кл, CTR ${q.ctr}, поз ${q.pos}`).join(' | ');

const now = new Date().toISOString();

// Build 4 context objects
const contexts = {
  seo: {
    updated_at: now,
    active_listings: pg.active,
    out_of_stock_visible: pg.oos,
    re_requiem_moderated: pg.re_ok,
    sessions_7d: ga.sess_7d,
    sessions_30d: ga.sess_30d,
    conv_rate_30d: ga.cr30 + '%',
    top_queries: tq || 'нет данных',
    alerts: [
      pg.oos > 5000 ? `🔴 ${pg.oos.toLocaleString()} OOS товаров видимы — thin content вредит индексации` : null,
      pg.oos > 1000 && pg.oos <= 5000 ? `⚠️ ${pg.oos.toLocaleString()} OOS товаров видимы` : null,
      !pg.re_ok ? '🔴 RE Requiem (ID:2067417) не промодерирован — не индексируется' : null,
      pg.pending > 10000 ? `🔴 ${pg.pending.toLocaleString()} товаров ожидают модерацию` : null,
    ].filter(Boolean)
  },
  strategy: {
    updated_at: now,
    revenue_yesterday: '€' + Number(ga.rev_yd).toFixed(0),
    revenue_7d: '€' + Number(ga.rev_7d).toFixed(0),
    revenue_30d: '€' + Number(ga.rev_30d).toFixed(0),
    revenue_avg_day: '€' + ga.avg_day,
    sessions_yesterday: ga.sess_yd,
    conversions_yesterday: ga.conv_yd,
    conv_rate_30d: ga.cr30 + '%',
    stuck_fulfilled: pg.stuck,
    completed_today: pg.comp_today,
    completed_7d: pg.comp_7d,
    completed_30d: pg.comp_30d,
    orders_7d: pg.orders_7d,
    alerts: [
      pg.stuck > 300 ? `🔴 ${pg.stuck} заказов застряли в fulfilled — продавцы не получают деньги` : null,
      pg.stuck > 50 && pg.stuck <= 300 ? `⚠️ ${pg.stuck} заказов в fulfilled` : null,
      Number(ga.rev_yd) < (Number(ga.rev_30d)/30 * 0.5) && Number(ga.rev_30d) > 0 ?
        `⚠️ Revenue вчера (€${Number(ga.rev_yd).toFixed(0)}) — ниже нормы на 50%+` : null,
    ].filter(Boolean)
  },
  marketing: {
    updated_at: now,
    sessions_yesterday: ga.sess_yd,
    sessions_7d: ga.sess_7d,
    sessions_30d: ga.sess_30d,
    conversions_30d: ga.conv_30d,
    conv_rate_30d: ga.cr30 + '%',
    revenue_30d: '€' + Number(ga.rev_30d).toFixed(0),
    revenue_7d: '€' + Number(ga.rev_7d).toFixed(0),
    orders_7d: pg.orders_7d,
    top_queries: tq || 'нет данных',
    alerts: [
      parseFloat(ga.cr30) < 5 ? `⚠️ Конверсия ${ga.cr30}% — сильно ниже цели 8%` : null,
      parseFloat(ga.cr30) >= 5 && parseFloat(ga.cr30) < 8 ? `📊 Конверсия ${ga.cr30}% — ниже цели 8%, есть потенциал` : null,
    ].filter(Boolean)
  },
  product: {
    updated_at: now,
    active_listings: pg.active,
    pending_moderation: pg.pending,
    out_of_stock_visible: pg.oos,
    stuck_fulfilled: pg.stuck,
    completed_today: pg.comp_today,
    orders_7d: pg.orders_7d,
    orders_24h: pg.orders_24h,
    new_reviews_7d: pg.reviews_7d,
    re_requiem_moderated: pg.re_ok,
    alerts: [
      pg.pending > 10000 ? `🔴 ${pg.pending.toLocaleString()} товаров ждут модерацию — критично` : null,
      pg.pending > 500 && pg.pending <= 10000 ? `⚠️ ${pg.pending.toLocaleString()} товаров на модерации` : null,
      !pg.re_ok ? '🔴 RE Requiem (ID:2067417) не промодерирован' : null,
      pg.stuck > 200 ? `⚠️ ${pg.stuck} заказов stuck в fulfilled` : null,
    ].filter(Boolean)
  }
};

// Return one item per manager for batch upsert
return Object.entries(contexts).map(([id, data]) => ({
  json: { manager_id: id, context_json: JSON.stringify(data) }
}));

const items = $input.all();
const updated = items.map(i => i.json.manager_id || 'ok').join(', ');
return [{ json: { message: `✅ Обновлено: ${updated}`, count: items.length } }];
